mapper.select:
SELECT EXISTS (
    SELECT 1 FROM transaction
    WHERE channel_id = #{channelId}
      AND external_tx_id = #{externalTxId}
)

SELECT t.transaction_id, t.channel_id, t.external_tx_id, t.amount, t.status, t.transacted_at, t.created_at
FROM transaction t
JOIN channel c ON t.channel_id = c.channel_id
WHERE c.seller_id = #{sellerId}
  AND DATE(t.transacted_at) = #{date}
  AND t.status = 'APPROVED'
